import{_ as r,c as i,o as s,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.25: Remember Your Work State","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.25.md","filePath":"en/changelog/v1.1.25.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.25.md"};function o(l,a,d,h,p,m){return s(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-25-remember-your-work-state" tabindex="-1">v1.1.25: Remember Your Work State <a class="header-anchor" href="#v1-1-25-remember-your-work-state" aria-label="Permalink to “v1.1.25: Remember Your Work State”">​</a></h1><p><strong>Release Date</strong>: January 16, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>Fixed some experience issues, desktop app now remembers your last opened project, no need to re-select every time.</p><hr><h2 id="improvement-remember-last-opened-project" tabindex="-1">Improvement: Remember Last Opened Project <a class="header-anchor" href="#improvement-remember-last-opened-project" aria-label="Permalink to “Improvement: Remember Last Opened Project”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Every time you reopen OpenCode desktop, you might need to re-select the project you want to enter, which is slightly troublesome.</p><h3 id="current-behavior" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior" aria-label="Permalink to “Current Behavior”">​</a></h3><p>The app is now smarter! It remembers the project you were using when you last closed it. When you open the app next time, you directly return to the familiar work state, seamless transition.</p><hr><h2 id="improvement-session-handling-optimization" tabindex="-1">Improvement: Session Handling Optimization <a class="header-anchor" href="#improvement-session-handling-optimization" aria-label="Permalink to “Improvement: Session Handling Optimization”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><ul><li><strong>More stable new session</strong>: Fixed some logic issues when handling new sessions in app</li><li><strong>Dialog centering</strong>: Various popup dialogs now display more elegantly centered on the page, not just in current session area, more visually balanced</li></ul><hr><h2 id="core-fix" tabindex="-1">Core Fix <a class="header-anchor" href="#core-fix" aria-label="Permalink to “Core Fix”">​</a></h2><h3 id="plugin-cache-fix" tabindex="-1">Plugin Cache Fix <a class="header-anchor" href="#plugin-cache-fix" aria-label="Permalink to “Plugin Cache Fix”">​</a></h3><p>Fixed an issue: when cache module is missing, plugins automatically reinstall. This ensures your plugin system is more stable, plugins won&#39;t become unusable because cache was accidentally deleted.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>OCD users</td><td>✅ Upgrade, fixed some small bugs</td></tr><tr><td>Lazy users</td><td>✅ Upgrade, remembering last project saves effort</td></tr><tr><td>Just upgraded v1.1.24</td><td>Suggest upgrading anyway, it&#39;s fast</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',23),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full changelog</summary><p><strong>Core</strong></p><ul><li>Optimize wording expression</li><li>Revert tool attachment fix, prevent them from being sent as user messages</li><li>Automatically reinstall plugins when cache module is missing</li></ul><p><strong>Desktop</strong></p><ul><li>Remember last opened project in app</li><li>Truncate long workspace titles in app</li><li>Fix new session handling in app</li><li>Center dialogs to page instead of session area</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=r(n,[["render",o]]);export{u as __pageData,g as default};
